#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 4e5+5;
const int INF = 0x3f3f3f3f;
int n,Q,c[N],ans[N];
struct node{
    int id,x,y,k;
}q[N],q1[N],q2[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void upd(int x,int k){while(x<=n)c[x]+=k,x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum+=c[x],x-=x&-x;return sum;}
void solve(int l,int r,int L,int R){
    if(L>R)return;
    if(l==r){
        for(int i=L;i<=R;i++)
            ans[q[i].id]=l;return;
    }
    int mid=(l+r)>>1,p1=0,p2=0;
    for(int i=L;i<=R;i++)
        if(!q[i].id)
            if(q[i].y<=mid)upd(q[i].x,1),q1[++p1]=q[i];
            else q2[++p2]=q[i];
        else{
            int cnt=ask(q[i].y)-ask(q[i].x-1);
            if(cnt>=q[i].k)q1[++p1]=q[i];
            else q[i].k-=cnt,q2[++p2]=q[i];
        }
    for(int i=1;i<=p1;i++)
        if(!q1[i].id)upd(q1[i].x,-1);
    for(int i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(int i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    solve(l,mid,L,L+p1-1);
    solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++){
        int x=read();
        q[i]={0,i,x,0};
    }
    for(int i=1;i<=Q;i++){
        int l=read(),r=read(),k=read();
        q[n+i]={i,l,r,k};
    }
    solve(0,INF,1,n+Q);
    for(int i=1;i<=Q;i++)cout<<ans[i]<<"\n";
    return 0;
}
